using Frame.DataAccess;
using Frame.BusinessLogic.Interfaces; using Microsoft.AspNetCore.Hosting; using Microsoft.AspNetCore.Http; using System; using System.IO; using System.Threading.Tasks;  namespace Frame.BusinessLogic.Services {     public class FileService : IFileService     {         public FileService()         {         }          public async Task<string> SaveFileAsync(IFormFile file, string folderName)         {             if (file == null || file.Length == 0)                 throw new ArgumentException("File is empty or null");              var uploadsFolder = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", folderName);             if (!Directory.Exists(uploadsFolder))             {                 Directory.CreateDirectory(uploadsFolder);             }              var uniqueFileName = Guid.NewGuid().ToString() + Path.GetExtension(file.FileName);             var filePath = Path.Combine(uploadsFolder, uniqueFileName);              using (var fileStream = new FileStream(filePath, FileMode.Create))             {                 await file.CopyToAsync(fileStream);             }              return $"/{folderName}/{uniqueFileName}";         }     } }
